package arrow.retrofit.adapter.either

import arrow.core.Either
import arrow.core.left
import arrow.core.right
import okhttp3.Request
import okhttp3.ResponseBody
import okio.Timeout
import retrofit2.Call
import retrofit2.CallAdapter
import retrofit2.Callback
import retrofit2.Converter
import retrofit2.Response
import retrofit2.Retrofit
import java.lang.reflect.Type

internal class ArrowEitherCallAdapter<E, R>(
  retrofit: Retrofit,
  errorType: Type,
  private val bodyType: Type,
) : CallAdapter<R, Call<Either<E, R>>> {

  private val errorConverter: Converter<ResponseBody, E> =
    retrofit.responseBodyConverter(errorType, arrayOf())

  override fun adapt(call: Call<R>): Call<Either<E, R>> = EitherCall(call, errorConverter, bodyType)

  override fun responseType(): Type = bodyType

  class EitherCall<E, R>(
    private val original: Call<R>,
    private val errorConverter: Converter<ResponseBody, E>,
    private val bodyType: Type,
  ) : Call<Either<E, R>> {

    override fun enqueue(callback: Callback<Either<E, R>>) {
      original.enqueue(object : Callback<R> {

        override fun onFailure(call: Call<R>, t: Throwable) {
          callback.onFailure(this@EitherCall, t)
        }

        override fun onResponse(call: Call<R>, response: Response<R>) {
          onResponseFn(
            callback,
            this@EitherCall,
            errorConverter,
            bodyType,
            response,
            { body, _ ->
              Response.success(response.code(), body.right())
            },
            { errorBody, _ ->
              Response.success(errorBody.left())
            },
          )
        }
      })
    }

    override fun isExecuted(): Boolean = original.isExecuted

    override fun timeout(): Timeout = original.timeout()

    override fun clone(): Call<Either<E, R>> = EitherCall(original.clone(), errorConverter, bodyType)

    override fun isCanceled(): Boolean = original.isCanceled

    override fun cancel() = original.cancel()

    override fun execute(): Response<Either<E, R>> {
      val response = original.execute()
      val result: Either<E, R> =
        response.body()?.right()
          ?: response.errorBody()?.let { errorConverter.convert(it) }?.left()
          ?: throw IllegalStateException()
      return Response.success(result, response.raw())
    }

    override fun request(): Request = original.request()
  }
}

package io.mockk.impl.annotations

import java.lang.reflect.InvocationTargetException
import kotlin.reflect.KClass
import kotlin.reflect.KClassifier
import kotlin.reflect.KMutableProperty1
import kotlin.reflect.KProperty
import kotlin.reflect.KProperty1
import kotlin.reflect.KType
import kotlin.reflect.jvm.isAccessible
import kotlin.reflect.jvm.javaField

internal object InjectionHelpers {
    @Suppress("UNCHECKED_CAST")
    fun KProperty1<*, *>.getAny(obj: Any): Any? {
        try {
            isAccessible = true
        } catch (ex: Throwable) {
            // skip
        }
        return (this.getter as KProperty1.Getter<Any, Any?>)(obj)
    }

    fun KProperty1<*, *>.getAnyIfLateNull(obj: Any): Any? {
        try {
            return getAny(obj)
        } catch (ex: InvocationTargetException) {
            if (isLateinit &&
                ex.cause != null &&
                ex.cause is UninitializedPropertyAccessException
            ) {
                return null
            }
            throw ex
        }
    }

    @Suppress("UNCHECKED_CAST")
    fun KMutableProperty1<*, *>.setAny(
        obj: Any,
        value: Any?,
    ) {
        try {
            isAccessible = true
        } catch (ex: Throwable) {
            // skip
        }
        return (this.setter as KMutableProperty1.Setter<Any, Any?>).invoke(obj, value)
    }

    fun KProperty1<*, *>.setImmutableAny(
        obj: Any,
        value: Any?,
    ) {
        val javaField = this.javaField ?: return
        try {
            javaField.isAccessible = true
        } catch (ex: Throwable) {
            // skip
        }
        javaField.set(obj, value)
    }

    fun KProperty<*>.getReturnTypeKClass(): KClass<*>? = returnType.classifier as? KClass<*>

    fun KType.getKClass(): KClass<*>? = classifier as? KClass<*>

    fun KClass<*>.getConstructorParameterTypes(): Set<KType> =
        constructors
            .flatMap { constructor ->
                constructor.parameters.map { it.type }
            }.toSet()

    fun isListType(classifier: KClassifier?): Boolean = classifier == List::class

    fun getListElementType(type: KType): KClass<*>? {
        val typeArg =
            type.arguments
                .firstOrNull()
                ?.type
                ?.classifier
        return typeArg as? KClass<*>
    }
}

